  1→"use client";
  2→
  3→import { useMemo, useRef, useState } from "react";
  4→import type { Offering } from "@/lib/api";
  5→import { buyerApi, defaultItemQty, type Order, type OrderCheckoutResponse } from "@/lib/buyer-api";
  6→import { orderToken } from "@/lib/order-token";
  7→import { PickupCodeCard } from "@/components/pickup-code-card";
  8→import { AuthorizeCard, isStripeAvailable } from "@/components/stripe-card-auth";
  9→import { useToast } from "@/components/toast";
 10→import { ErrorAlert } from "@/components/error-alert";
 11→import { formatMoney, friendlyErrorMessage } from "@/lib/ui";
 12→
 13→export type PickupInfo = {
 14→  date: string;
 15→  time: string;
 16→  locationName: string | null;
 17→  locationAddress: string;
 18→};
 19→
 20→export function CheckoutForm({
 21→  pickupWindowId,
 22→  offerings,
 23→  pickupInfo,
 24→}: {
 25→  pickupWindowId: string;
 26→  offerings: Offering[];
 27→  pickupInfo?: PickupInfo;
 28→}) {
 29→  const { showToast } = useToast();
 30→  const [qty, setQty] = useState<Record<string, number>>(() =>
 31→    defaultItemQty(offerings),
 32→  );
 33→  const [buyerEmail, setBuyerEmail] = useState("");
 34→  const [buyerName, setBuyerName] = useState("");
 35→  const [buyerPhone, setBuyerPhone] = useState("");
 36→  const [submitting, setSubmitting] = useState(false);
 37→  const [error, setError] = useState<string | null>(null);
 38→  const [order, setOrder] = useState<Order | null>(null);
 39→  const [copied, setCopied] = useState(false);
 40→  const [checkout, setCheckout] = useState<OrderCheckoutResponse | null>(null);
 41→  // Snapshot of items at checkout time — ensures the order matches the authorized amount
 42→  const [checkoutItems, setCheckoutItems] = useState<
 43→    { offering_id: string; quantity: number }[] | null
 44→  >(null);
 45→  const startingCheckoutRef = useRef(false);
 46→  const formLocked = !!checkout;
 47→
 48→  const items = useMemo(() => {
 49→    return offerings
 50→      .map((o) => ({ offering_id: o.id, quantity: qty[o.id] ?? 0, offering: o }))
 51→      .filter((x) => x.quantity > 0);
 52→  }, [offerings, qty]);
 53→
 54→  const total = useMemo(() => {
 55→    return items.reduce((sum, it) => sum + it.offering.price_cents * it.quantity, 0);
 56→  }, [items]);
 57→
 58→  const priceSubtotal = checkout?.subtotal_cents ?? total;
 59→  const priceFee = checkout?.buyer_fee_cents ?? 0;
 60→  const priceTotal = checkout?.total_cents ?? total;
 61→  const feeBps = checkout?.buyer_fee_bps ?? null;
 62→  const feeFlat = checkout?.buyer_fee_flat_cents ?? null;
 63→  const feeLabel = (() => {
 64→    const parts: string[] = [];
 65→    if (feeBps !== null && feeBps > 0) parts.push(`${(feeBps / 100).toFixed(0)}%`);
 66→    if (feeFlat !== null && feeFlat > 0) parts.push(formatMoney(feeFlat));
 67→    return parts.length > 0 ? parts.join(" + ") : null;
 68→  })();
 69→
 70→  async function startCardCheckout() {
 71→    if (startingCheckoutRef.current) return;
 72→    if (!isStripeAvailable()) {
 73→      setError("Payment system could not load. Please disable ad blockers and refresh.");
 74→      return;
 75→    }
 76→    startingCheckoutRef.current = true;
 77→    setSubmitting(true);
 78→    setError(null);
 79→    try {
 80→      const snapshotItems = items.map((it) => ({
 81→        offering_id: it.offering_id,
 82→        quantity: it.quantity,
 83→      }));
 84→      const res = await buyerApi.checkoutOrder(pickupWindowId, {
 85→        buyer: {
 86→          email: buyerEmail,
 87→          name: buyerName || null,
 88→          phone: buyerPhone || null,
 89→        },
 90→        items: snapshotItems,
 91→      });
 92→      setCheckoutItems(snapshotItems);
 93→      setCheckout(res);
 94→      showToast({ kind: "success", message: "Card authorization started." });
 95→    } catch (e: unknown) {
 96→      setError(friendlyErrorMessage(e));
 97→    } finally {
 98→      setSubmitting(false);
 99→      startingCheckoutRef.current = false;
100→    }
101→  }
102→
103→  async function completeCardOrder() {
104→    if (!checkout || !checkoutItems) return;
105→    try {
106→      const res = await buyerApi.placeOrder(pickupWindowId, {
107→        buyer: {
108→          email: buyerEmail,
109→          name: buyerName || null,
110→          phone: buyerPhone || null,
111→        },
112→        // Use the snapshot from checkout time — matches the authorized amount
113→        items: checkoutItems,
114→        stripe_payment_intent_id: checkout.payment_intent_id,
115→        payment_method: "card",
116→      });
117→      orderToken.set(res.id, res.buyer_token);
118→      setOrder(res);
119→      showToast({ kind: "success", message: "Order placed." });
120→    } catch {
121→      // Card is already authorized — keep checkout state so user can retry
122→      // without re-authorizing their card.
123→      setError(
124→        "Your card was authorized, but we couldn\u2019t place your order. " +
125→        "Please tap \u201cAuthorize card\u201d again to retry. " +
126→        "If the problem persists, contact support \u2014 your card will not be charged.",
127→      );
128→      // Re-throw with sentinel so AuthorizeCard resets submitting without
129→      // overwriting our detailed error message.
130→      throw new Error("__handled__");
131→    }
132→  }
133→
134→  async function copyAccessLink() {
135→    if (!order) return;
136→    const url = `${window.location.origin}/orders/${order.id}?t=${encodeURIComponent(order.buyer_token)}`;
137→    try {
138→      await navigator.clipboard.writeText(url);
139→      setCopied(true);
140→      setTimeout(() => setCopied(false), 1400);
141→      showToast({ kind: "success", message: "Access link copied." });
142→    } catch {
143→      showToast({
144→        kind: "error",
145→        message: "Could not copy. Your browser may block clipboard access.",
146→      });
147→    }
148→  }
149→
150→  if (order) {
151→    return (
152→      <div className="grid gap-4">
153→        <section className="lr-card lr-card-strong p-6">
154→          <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
155→            Order placed
156→          </h2>
157→          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">
158→            Order ID: <span className="font-mono text-xs">{order.id}</span>
159→          </p>
160→          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">
161→            Total:{" "}
162→            <span className="font-medium text-[color:var(--lr-ink)]">
163→              {formatMoney(order.total_cents)}
164→            </span>
165→          </p>
166→          <div className="mt-4 grid gap-2 rounded-xl bg-white/60 p-4 ring-1 ring-[color:var(--lr-border)]">
167→            <div className="text-sm font-medium text-[color:var(--lr-ink)]">
168→              Save your access link
169→            </div>
170→            <div className="text-sm text-[color:var(--lr-muted)]">
171→              You will need it to check status or leave a review on another
172→              device.
173→            </div>
174→            <div className="flex flex-wrap gap-2">
175→              <a
176→                className="lr-btn px-4 py-2 text-sm font-medium text-[color:var(--lr-ink)]"
177→                href={`/orders/${order.id}`}
178→              >
179→                View order
180→              </a>
181→              <button
182→                className="lr-btn lr-btn-primary px-4 py-2 text-sm font-medium"
183→                type="button"
184→                onClick={copyAccessLink}
185→              >
186→                {copied ? "Copied" : "Copy access link"}
187→              </button>
188→            </div>
189→          </div>
190→
191→          <div className="mt-4 rounded-xl bg-white/60 p-4 text-sm text-[color:var(--lr-muted)] ring-1 ring-[color:var(--lr-border)]">
192→            Payment:{" "}
193→            <span className="font-medium">
194→              Card authorized — captured on pickup
195→            </span>
196→          </div>
197→
198→          {pickupInfo ? (
199→            <div className="mt-4 rounded-xl bg-white/60 p-4 ring-1 ring-[color:var(--lr-border)]">
200→              <div className="text-sm font-medium text-[color:var(--lr-ink)]">
201→                Pickup details
202→              </div>
203→              <div className="mt-2 grid gap-1 text-sm text-[color:var(--lr-muted)]">
204→                <div>
205→                  {pickupInfo.date} at {pickupInfo.time}
206→                </div>
207→                <div>
208→                  {pickupInfo.locationName ? (
209→                    <span className="font-medium text-[color:var(--lr-ink)]">
210→                      {pickupInfo.locationName}
211→                    </span>
212→                  ) : null}
213→                  {pickupInfo.locationName ? " · " : ""}
214→                  {pickupInfo.locationAddress}
215→                </div>
216→              </div>
217→            </div>
218→          ) : null}
219→        </section>
220→
221→        <PickupCodeCard
222→          storeId={order.store_id}
223→          orderId={order.id}
224→          pickupCode={order.pickup_code}
225→          status={order.status}
226→        />
227→      </div>
228→    );
229→  }
230→
231→  return (
232→    <section className="lr-card lr-card-strong p-6">
233→      <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
234→        Checkout
235→      </h2>
236→      <p className="mt-1 text-sm text-[color:var(--lr-muted)]">
237→        Select quantities, then place an order for local pickup.
238→      </p>
239→
240→      {error ? <ErrorAlert error={error} className="mt-4" /> : null}
241→
242→      <div className="mt-4 grid gap-3">
243→        {offerings.map((o) => {
244→          const remaining = o.quantity_remaining ?? 0;
245→          const cur = qty[o.id] ?? 0;
246→          return (
247→            <div
248→              key={o.id}
249→              className={`flex flex-wrap items-center justify-between gap-3 rounded-xl px-4 py-3 ring-1 ring-[color:var(--lr-border)] ${remaining === 0 ? "bg-white/30 opacity-60" : "bg-white/60"}`}
250→            >
251→              <div>
252→                <div className="font-medium text-[color:var(--lr-ink)]">
253→                  {o.product.title}
254→                </div>
255→                <div className="text-sm text-[color:var(--lr-muted)]">
256→                  {formatMoney(o.price_cents)} &middot; {o.product.unit} &middot; {remaining} left
257→                </div>
258→              </div>
259→              <input
260→                className="lr-field w-20 sm:w-24 px-3 py-2 text-sm"
261→                type="number"
262→                min={0}
263→                max={remaining}
264→                value={cur}
265→                disabled={formLocked || remaining === 0}
266→                onChange={(e) =>
267→                  setQty((prev) => ({
268→                    ...prev,
269→                    [o.id]: Math.max(0, Math.min(remaining, Number(e.target.value) || 0)),
270→                  }))
271→                }
272→              />
273→            </div>
274→          );
275→        })}
276→      </div>
277→
278→      <div className="mt-4 grid gap-2 rounded-xl bg-white/60 p-4 ring-1 ring-[color:var(--lr-border)]">
279→        <div className="grid gap-2">
280→          <div className="flex items-baseline justify-between gap-4">
281→            <span className="text-sm font-medium text-[color:var(--lr-muted)]">Subtotal</span>
282→            <span className="text-sm font-semibold text-[color:var(--lr-ink)]">
283→              {formatMoney(priceSubtotal)}
284→            </span>
285→          </div>
286→          <div className="flex items-baseline justify-between gap-4">
287→            <span className="text-sm font-medium text-[color:var(--lr-muted)]">
288→              Service fee{feeLabel ? ` (${feeLabel})` : ""}
289→            </span>
290→            <span className="text-sm font-semibold text-[color:var(--lr-ink)]">
291→              {checkout ? formatMoney(priceFee) : "Calculated at checkout"}
292→            </span>
293→          </div>
294→          <div className="h-px bg-[color:var(--lr-border)]/70" />
295→          <div className="flex items-baseline justify-between gap-4">
296→            <span className="text-sm font-semibold text-[color:var(--lr-ink)]">Total</span>
297→            <span className="text-sm font-semibold text-[color:var(--lr-ink)]">
298→              {checkout ? formatMoney(priceTotal) : `${formatMoney(priceTotal)} + fee`}
299→            </span>
300→          </div>
301→        </div>
302→
303→        <label className="grid gap-1">
304→          <span className="text-xs font-medium text-[color:var(--lr-muted)]">
305→            Email
306→          </span>
307→          <input
308→            className="lr-field px-3 py-2 text-sm"
309→            type="email"
310→            value={buyerEmail}
311→            onChange={(e) => setBuyerEmail(e.target.value)}
312→            required
313→            disabled={formLocked}
314→          />
315→        </label>
316→        <div className="grid gap-2 md:grid-cols-2">
317→          <label className="grid gap-1">
318→            <span className="text-xs font-medium text-[color:var(--lr-muted)]">
319→              Name (optional)
320→            </span>
321→            <input
322→              className="lr-field px-3 py-2 text-sm"
323→              value={buyerName}
324→              onChange={(e) => setBuyerName(e.target.value)}
325→              disabled={formLocked}
326→            />
327→          </label>
328→          <label className="grid gap-1">
329→            <span className="text-xs font-medium text-[color:var(--lr-muted)]">
330→              Phone (optional)
331→            </span>
332→            <input
333→              className="lr-field px-3 py-2 text-sm"
334→              type="tel"
335→              value={buyerPhone}
336→              onChange={(e) => setBuyerPhone(e.target.value)}
337→              disabled={formLocked}
338→              placeholder="(555) 555-1234"
339→            />
340→          </label>
341→        </div>
342→
343→        <button
344→          type="button"
345→          className={`lr-btn lr-btn-primary mt-2 inline-flex items-center justify-center px-4 py-2 text-sm font-medium disabled:opacity-50${checkout ? " cursor-not-allowed" : ""}`}
346→          disabled={submitting || items.length === 0 || !buyerEmail.trim() || !!checkout}
347→          onClick={startCardCheckout}
348→        >
349→          {checkout
350→            ? "Complete payment below"
351→            : submitting
352→              ? "Starting\u2026"
353→              : "Continue to payment"}
354→        </button>
355→        {checkout ? (
356→          <AuthorizeCard
357→            clientSecret={checkout.client_secret}
358→            submitting={submitting}
359→            setSubmitting={setSubmitting}
360→            setError={setError}
361→            onAuthorized={completeCardOrder}
362→            mode="payment_intent"
363→          />
364→        ) : null}
365→      </div>
366→    </section>
367→  );
368→}
