  1→"use client";
  2→
  3→import { useParams, useRouter } from "next/navigation";
  4→import { useEffect, useState } from "react";
  5→import {
  6→  sellerApi,
  7→  type SellerPickupLocation,
  8→  type SellerSubscriptionPlan,
  9→} from "@/lib/seller-api";
 10→import { session } from "@/lib/session";
 11→import { useToast } from "@/components/toast";
 12→import { formatMoney, friendlyErrorMessage } from "@/lib/ui";
 13→import { QrCode } from "@/components/qr-code";
 14→
 15→function cadenceLabel(cadence: string): string {
 16→  switch (cadence) {
 17→    case "weekly":
 18→      return "/week";
 19→    case "biweekly":
 20→      return "/2 weeks";
 21→    case "monthly":
 22→      return "/month";
 23→    default:
 24→      return "";
 25→  }
 26→}
 27→
 28→function friendlyDate(iso: string, tz?: string): string {
 29→  const opts: Intl.DateTimeFormatOptions = {
 30→    weekday: "short",
 31→    month: "short",
 32→    day: "numeric",
 33→    hour: "numeric",
 34→    minute: "2-digit",
 35→  };
 36→  if (tz) opts.timeZone = tz;
 37→  return new Date(iso).toLocaleDateString(undefined, opts);
 38→}
 39→
 40→export default function ReviewPage() {
 41→  const params = useParams<{ storeId: string }>();
 42→  const storeId = params.storeId;
 43→  const router = useRouter();
 44→  const { showToast } = useToast();
 45→
 46→  const [loading, setLoading] = useState(true);
 47→  const [launching, setLaunching] = useState(false);
 48→  const [location, setLocation] = useState<SellerPickupLocation | null>(null);
 49→  const [plan, setPlan] = useState<SellerSubscriptionPlan | null>(null);
 50→  const [launched, setLaunched] = useState(false);
 51→  const [copied, setCopied] = useState(false);
 52→
 53→  useEffect(() => {
 54→    const token = session.getToken();
 55→    if (!token) {
 56→      router.replace("/seller/login");
 57→      return;
 58→    }
 59→
 60→    let cancelled = false;
 61→
 62→    async function load() {
 63→      try {
 64→        const [locations, plans] = await Promise.all([
 65→          sellerApi.listPickupLocations(token!, storeId),
 66→          sellerApi.listSubscriptionPlans(token!, storeId),
 67→        ]);
 68→
 69→        if (cancelled) return;
 70→
 71→        if (locations.length === 0) {
 72→          router.replace(`/seller/stores/${storeId}/setup/location`);
 73→          return;
 74→        }
 75→
 76→        if (plans.length === 0) {
 77→          router.replace(`/seller/stores/${storeId}/setup/box`);
 78→          return;
 79→        }
 80→
 81→        setLocation(locations[0]);
 82→        setPlan(plans.find((p) => p.is_active) ?? plans[0]);
 83→      } catch (e: unknown) {
 84→        if (!cancelled) {
 85→          showToast({ kind: "error", message: friendlyErrorMessage(e) });
 86→        }
 87→      } finally {
 88→        if (!cancelled) setLoading(false);
 89→      }
 90→    }
 91→
 92→    load();
 93→    return () => {
 94→      cancelled = true;
 95→    };
 96→    // eslint-disable-next-line react-hooks/exhaustive-deps
 97→  }, [storeId]);
 98→
 99→  async function handleLaunch() {
100→    const token = session.getToken();
101→    if (!token || !plan) return;
102→
103→    setLaunching(true);
104→    try {
105→      await sellerApi.generateNextCycle(token, storeId, plan.id);
106→      showToast({ kind: "success", message: "You're live!" });
107→      setLaunched(true);
108→    } catch (e: unknown) {
109→      showToast({ kind: "error", message: friendlyErrorMessage(e) });
110→    } finally {
111→      setLaunching(false);
112→    }
113→  }
114→
115→  async function handleCopy(url: string) {
116→    try {
117→      await navigator.clipboard.writeText(url);
118→      setCopied(true);
119→      showToast({ kind: "success", message: "Link copied!" });
120→      setTimeout(() => setCopied(false), 2000);
121→    } catch {
122→      showToast({ kind: "error", message: "Could not copy to clipboard." });
123→    }
124→  }
125→
126→  if (loading) {
127→    return (
128→      <div className="flex items-center justify-center py-12">
129→        <div
130→          className="h-6 w-6 rounded-full border-2 border-[color:var(--lr-leaf)] border-t-transparent animate-spin"
131→          role="status"
132→          aria-label="Loading"
133→        />
134→      </div>
135→    );
136→  }
137→
138→  if (!location || !plan) return null;
139→
140→  const shareUrl =
141→    typeof window !== "undefined"
142→      ? `${window.location.origin}/stores/${storeId}/boxes`
143→      : "";
144→
145→  // ── Celebration view ──
146→  if (launched) {
147→    return (
148→      <div className="lr-animate grid justify-items-center gap-6 text-center">
149→        {/* Checkmark */}
150→        <div
151→          className="flex h-16 w-16 items-center justify-center rounded-full"
152→          style={{ backgroundColor: "var(--lr-leaf)" }}
153→        >
154→          <svg
155→            width="32"
156→            height="32"
157→            viewBox="0 0 32 32"
158→            fill="none"
159→            aria-hidden="true"
160→          >
161→            <path
162→              d="M8 17L13.5 22.5L24 10"
163→              stroke="#fff"
164→              strokeWidth="3"
165→              strokeLinecap="round"
166→              strokeLinejoin="round"
167→            />
168→          </svg>
169→        </div>
170→
171→        <div>
172→          <h1 className="text-2xl font-bold text-[color:var(--lr-ink)]">
173→            You&apos;re live!
174→          </h1>
175→          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">
176→            Your farmstand is open for business. Share the link or QR code with
177→            your customers so they can subscribe.
178→          </p>
179→        </div>
180→
181→        {/* QR code */}
182→        <QrCode value={shareUrl} size={180} label="Farmstand QR code" />
183→
184→        {/* Shareable URL */}
185→        <div className="w-full max-w-sm">
186→          <div className="lr-card-strong flex items-center gap-2 rounded-xl p-3">
187→            <span className="min-w-0 flex-1 truncate text-sm text-[color:var(--lr-ink)]">
188→              {shareUrl}
