  const formLocked = !!checkout;
  const priceSubtotal = checkout?.subtotal_cents ?? plan.price_cents;
  const priceFee = checkout?.buyer_fee_cents ?? 0;
  const priceTotal = checkout?.total_cents ?? plan.price_cents;
  const depositCents = checkout?.deposit_cents ?? plan.deposit_cents ?? 0;
  const feeBps = checkout?.buyer_fee_bps ?? null;
  const feeFlat = checkout?.buyer_fee_flat_cents ?? null;
  const feeLabel = (() => {
    const parts: string[] = [];
    if (feeBps !== null && feeBps > 0) parts.push(`${(feeBps / 100).toFixed(0)}%`);
    if (feeFlat !== null && feeFlat > 0) parts.push(formatMoney(feeFlat));
    return parts.length > 0 ? parts.join(" + ") : null;
  })();

  const nextLabel = useMemo(() => {
    const tz = plan.pickup_location.timezone || "UTC";
    const start = new Date(plan.next_start_at);
    return new Intl.DateTimeFormat("en-US", {
      timeZone: tz,
      weekday: "short",
      month: "short",
      day: "numeric",
      hour: "numeric",
      minute: "2-digit",
    }).format(start);
  }, [plan.next_start_at, plan.pickup_location.timezone]);

  async function startCheckout() {
    if (startingCheckoutRef.current) return;
    if (!isStripeAvailable()) {
      setError("Payment system could not load. Please disable ad blockers and refresh.");
      return;
    }
