"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useState } from "react";
import {
  buyerAuthApi,
  type BuyerAuthUser,
  type BuyerOrderSummary,
  type BuyerSubscriptionSummary,
} from "@/lib/buyer-api";
import { session } from "@/lib/session";
import { ErrorAlert } from "@/components/error-alert";
import { PickupCodeCard } from "@/components/pickup-code-card";
import { useToast } from "@/components/toast";
import { formatMoney, friendlyErrorMessage, parseApiError } from "@/lib/ui";

function cadenceLabel(c: string) {
  if (c === "weekly") return "Weekly";
  if (c === "biweekly") return "Every two weeks";
  if (c === "monthly") return "Monthly";
  return c;
}

function statusBadge(status: string) {
  const colors: Record<string, string> = {
    placed: "bg-blue-50 text-blue-800 ring-blue-200",
    ready: "bg-green-50 text-green-800 ring-green-200",
    picked_up: "bg-emerald-50 text-emerald-800 ring-emerald-200",
    canceled: "bg-gray-50 text-gray-600 ring-gray-200",
    no_show: "bg-rose-50 text-rose-800 ring-rose-200",
    active: "bg-green-50 text-green-800 ring-green-200",
    paused: "bg-amber-50 text-amber-800 ring-amber-200",
  };
  return (
    <span
      className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ring-1 ${colors[status] ?? "bg-gray-50 text-gray-600 ring-gray-200"}`}
    >
      {status.replace(/_/g, " ")}
    </span>
  );
}

export default function BuyerDashboardPage() {
  const router = useRouter();
  const { showToast } = useToast();
  const [user, setUser] = useState<BuyerAuthUser | null>(null);
  const [orders, setOrders] = useState<BuyerOrderSummary[]>([]);
  const [subscriptions, setSubscriptions] = useState<BuyerSubscriptionSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => { document.title = "My pickups — LocalRoots"; }, []);

  const load = useCallback(async () => {
    const token = session.getToken();
    if (!token) {
      router.replace("/buyer/login");
      return;
    }
    try {
      const [me, ords, subs] = await Promise.all([
        buyerAuthApi.getMe(token),
        buyerAuthApi.listOrders(token),
        buyerAuthApi.listSubscriptions(token),
      ]);
      setUser(me);
      setOrders(ords);
      setSubscriptions(subs);
    } catch (err: unknown) {
      const apiErr = parseApiError(err);
      if (apiErr && (apiErr.status === 401 || apiErr.status === 403)) {
        session.clearToken();
        showToast({
          kind: "error",
          message: "Your session has expired. Please sign in again.",
        });
        router.replace("/buyer/login");
        return;
      }
      setError(friendlyErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }, [router, showToast]);

  useEffect(() => {
    load();
  }, [load]);

  function signOut() {
    session.clearToken();
    router.replace("/buyer/login");
  }

  if (loading) {
    return (
      <section className="lr-card lr-card-strong p-6 text-center">
        <p className="text-sm text-[color:var(--lr-muted)]">Loading...</p>
      </section>
    );
  }

  if (error) {
    return (
      <section className="lr-card lr-card-strong p-6">
        <ErrorAlert
          error={error}
          onRetry={() => {
            setError(null);
            setLoading(true);
            load();
          }}
        />
      </section>
    );
  }

  if (!user) return null;

  const upcomingOrders = orders
    .filter((o) => ["placed", "ready"].includes(o.status))
    .sort(
      (a, b) =>
        new Date(a.pickup_start_at).getTime() -
        new Date(b.pickup_start_at).getTime(),
    );
  const pastOrders = orders.filter(
    (o) => !["placed", "ready"].includes(o.status),
  );
  const activeSubs = subscriptions.filter((s) => s.status !== "canceled");

  return (
    <div className="grid gap-6">
      <section className="lr-card lr-card-strong p-6">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div>
            <h1 className="text-lg font-semibold text-[color:var(--lr-ink)]">
              My pickups
            </h1>
            <p className="mt-1 text-sm text-[color:var(--lr-muted)]">
              {user.email}
            </p>
          </div>
          <button
            type="button"
            className="lr-btn px-3 py-1.5 text-xs font-semibold text-[color:var(--lr-muted)]"
            onClick={signOut}
          >
            Sign out
          </button>
        </div>
      </section>

      <section className="lr-card p-6">
        <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
          Active Subscriptions
        </h2>
        {activeSubs.length > 0 ? (
          <div className="mt-3 grid gap-2">
            {activeSubs.map((s) => (
              <Link
                key={s.id}
                href={`/subscriptions/${s.id}`}
                className="flex flex-wrap items-center justify-between gap-2 rounded-xl bg-white/60 p-3 ring-1 ring-[color:var(--lr-border)] transition-colors hover:bg-white/80"
              >
                <div>
                  <div className="text-sm font-semibold text-[color:var(--lr-ink)]">
                    {s.plan_title}
                  </div>
                  <div className="text-xs text-[color:var(--lr-muted)]">
                    {s.store_name ? `${s.store_name} · ` : ""}
                    {cadenceLabel(s.cadence)} · {formatMoney(s.price_cents)}
                  </div>
                </div>
                {statusBadge(s.status)}
              </Link>
            ))}
          </div>
        ) : (
          <p className="mt-3 text-sm text-[color:var(--lr-muted)]">
            No active subscriptions yet.{" "}
            <Link className="underline" href="/stores">
              Browse farms
            </Link>
          </p>
        )}
      </section>

      <section className="lr-card p-6">
        <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
          Upcoming Pickups
        </h2>
        {upcomingOrders.length > 0 ? (
          <div className="mt-3 grid gap-3">
            {upcomingOrders.map((o) => (
              <Link
                key={o.id}
                href={`/orders/${o.id}?t=${encodeURIComponent(session.getToken() ?? "")}`}
                className="block rounded-xl bg-white/60 ring-1 ring-[color:var(--lr-border)] transition hover:-translate-y-0.5 hover:shadow-[0_22px_60px_rgba(38,28,10,0.14)]"
              >
                <div className="flex flex-wrap items-center justify-between gap-2 p-3">
                  <div>
                    <div className="text-sm font-semibold text-[color:var(--lr-ink)]">
                      {o.product_title || "Order"}
                    </div>
                    <div className="text-xs text-[color:var(--lr-muted)]">
                      {new Date(o.pickup_start_at).toLocaleDateString("en-US", {
                        weekday: "short",
                        month: "short",
                        day: "numeric",
                        hour: "numeric",
                        minute: "2-digit",
                      })}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {statusBadge(o.status)}
                    <span className="text-sm font-semibold text-[color:var(--lr-ink)]">
                      {formatMoney(o.total_cents)}
                    </span>
                  </div>
                </div>
                <div className="border-t border-[color:var(--lr-border)]/70 px-3 pb-3 pt-2">
                  <PickupCodeCard
                    storeId={o.store_id}
                    orderId={o.id}
                    pickupCode={o.pickup_code}
                    status={o.status}
                  />
                </div>
              </Link>
            ))}
          </div>
        ) : (
          <p className="mt-3 text-sm text-[color:var(--lr-muted)]">
            No upcoming pickups.{" "}
            <Link className="underline" href="/stores">
              Browse boxes
            </Link>
          </p>
        )}
      </section>

      <section className="lr-card p-6">
        <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
          Past Orders
        </h2>
        {pastOrders.length > 0 ? (
          <div className="mt-3 grid gap-2">
            {pastOrders.slice(0, 10).map((o) => (
              <Link
                key={o.id}
                href={`/orders/${o.id}?t=${encodeURIComponent(session.getToken() ?? "")}`}
                className="flex flex-wrap items-center justify-between gap-2 rounded-xl bg-white/60 p-3 ring-1 ring-[color:var(--lr-border)] transition hover:-translate-y-0.5 hover:shadow-[0_22px_60px_rgba(38,28,10,0.14)]"
              >
                <div>
                  <div className="text-sm font-medium text-[color:var(--lr-ink)]">
                    {o.product_title || "Order"}
                  </div>
                  <div className="text-xs text-[color:var(--lr-muted)]">
                    {new Date(o.created_at).toLocaleDateString("en-US", {
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    })}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  {statusBadge(o.status)}
                  <span className="text-sm text-[color:var(--lr-muted)]">
                    {formatMoney(o.total_cents)}
                  </span>
                </div>
              </Link>
            ))}
          </div>
        ) : (
          <p className="mt-3 text-sm text-[color:var(--lr-muted)]">
            No past orders.
          </p>
        )}
      </section>
    </div>
  );
}

import { headers } from "next/headers";
import Link from "next/link";

import { requestJSON } from "@/lib/http";
import { PrintPosterActions } from "@/components/print-poster-actions";

type Plan = {
  id: string;
  store_id: string;
  title: string;
  cadence: string;
  price_cents: number;
  subscriber_limit: number;
  first_start_at: string;
  duration_minutes: number;
  cutoff_hours: number;
  is_active: boolean;
  is_live: boolean;
  next_start_at: string;
  pickup_location: {
    id: string;
    label: string | null;
    address1: string;
    city: string;
    region: string;
    postal_code: string;
    timezone: string;
  };
};

async function requestOrigin() {
  const h = await headers();
  const proto = h.get("x-forwarded-proto") ?? "https";
  const host = h.get("x-forwarded-host") ?? h.get("host");
  if (!host) return "";
  return `${proto}://${host}`;
}

function formatMoney(cents: number) {
  return `$${(cents / 100).toFixed(2)}`;
}

function cadenceLabel(c: string) {
  if (c === "weekly") return "Weekly";
  if (c === "biweekly") return "Every two weeks";
  if (c === "monthly") return "Monthly";
  return c;
}

async function qrDataUrl(value: string, size: number) {
  const mod = await import("qrcode");
  return await mod.toDataURL(value, {
    margin: 1,
    width: size,
    color: { dark: "#1c1b16", light: "#ffffff" },
  });
}

export default async function BoxQrPosterPage({
  params,
}: {
  params: Promise<{ planId: string }>;
}) {
  const { planId } = await params;
  const plan = await requestJSON<Plan>(`/v1/subscription-plans/${planId}`, {
    next: { revalidate: 60 },
  });

  const origin = await requestOrigin();
  const shortUrl = origin ? `${origin}/b/${planId}` : `/b/${planId}`;
  const boxUrl = origin ? `${origin}/boxes/${planId}` : `/boxes/${planId}`;
  const qr = await qrDataUrl(shortUrl, 640);

  const tz = plan.pickup_location.timezone || "UTC";
  const nextStart = new Date(plan.next_start_at);
  const nextLabel = new Intl.DateTimeFormat("en-US", {
    timeZone: tz,
    weekday: "long",
    month: "long",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  }).format(nextStart);

  const where = `${plan.pickup_location.address1}, ${plan.pickup_location.city}, ${plan.pickup_location.region} ${plan.pickup_location.postal_code}`;

  return (
    <div className="min-h-[100svh] bg-[linear-gradient(180deg,rgba(255,246,228,0.96),rgba(243,231,200,0.92))] p-6 text-[color:var(--lr-ink)]">
      <div className="mx-auto grid w-full max-w-3xl gap-6">
        <div className="print:hidden">
          <Link
            className="lr-btn lr-chip inline-flex w-fit items-center gap-2 px-4 py-2 text-sm font-medium text-[color:var(--lr-ink)]"
            href={`/boxes/${planId}`}
          >
            <span aria-hidden="true">←</span>
            Back to buyer page
          </Link>
        </div>

        <section className="rounded-[2rem] bg-white/70 p-8 shadow-[0_30px_90px_rgba(38,28,10,0.12)] ring-1 ring-[color:var(--lr-border)] print:shadow-none print:ring-0">
          <div className="flex flex-wrap items-start justify-between gap-6">
            <div className="grid gap-2">
              <div className="text-xs font-semibold uppercase tracking-wide text-[color:var(--lr-muted)]">
                LocalRoots
              </div>
              <h1 className="text-3xl font-semibold tracking-tight">
                {plan.title}
              </h1>
              <div className="text-sm text-[color:var(--lr-muted)]">
                {cadenceLabel(plan.cadence)} subscription box
              </div>
              <div className="mt-2 grid gap-1 text-sm">
                <div>
                  <span className="font-semibold">Price:</span>{" "}
                  {formatMoney(plan.price_cents)} + service fee
                </div>
                <div>
                  <span className="font-semibold">Next pickup:</span> {nextLabel}
                </div>
                <div>
                  <span className="font-semibold">Pickup:</span> {where}
                </div>
              </div>
            </div>

            <div className="grid justify-items-center gap-3">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={qr}
                alt="Subscribe QR code"
                className="rounded-3xl border border-[color:var(--lr-border)] bg-white p-4"
                style={{ width: 360, height: 360 }}
              />
              <div className="text-center text-sm font-semibold">
                Scan to subscribe
              </div>
              <div className="text-center text-xs text-[color:var(--lr-muted)]">
                Or visit:{" "}
                <span className="font-mono break-all">{shortUrl}</span>
              </div>
            </div>
          </div>

          <div className="mt-6 rounded-2xl bg-[rgba(47,107,79,0.08)] p-4 text-sm text-[color:var(--lr-ink)] ring-1 ring-[rgba(47,107,79,0.18)]">
            Payment is authorized in advance and captured when pickup is
            confirmed.
          </div>
        </section>

        <PrintPosterActions boxUrl={boxUrl} />
      </div>
    </div>
  );
}

