      return;
    }
    startingCheckoutRef.current = true;
    setSubmitting(true);
    setError(null);
    try {
      const res = await buyerApi.checkoutPlan(plan.id, {
        buyer: {
          email,
          name: name || null,
          phone: phone || null,
        },
      });
      setCheckout(res);
      showToast({
        kind: "success",
        message:
          res.mode === "payment_intent"
            ? "Card authorization started."
            : "Card setup started.",
      });
    } catch (e: unknown) {
